"use client";

import Image from "next/image";
import Link from "next/link";
import { motion } from "framer-motion";
import { ArrowRight, Flame, Star } from "lucide-react";

const trendingProducts = [
  {
    id: 1,
    title: "Nike Air Max",
    category: "Sneakers",
    price: "₹5,999",
    oldPrice: "₹8,999",
    image:
      "https://images.unsplash.com/photo-1542291026-7eec264c27ff?q=80&w=1200&auto=format&fit=crop",
  },
  {
    id: 2,
    title: "Apple Watch Ultra",
    category: "Smart Watch",
    price: "₹79,999",
    oldPrice: "₹92,999",
    image:
      "https://images.unsplash.com/photo-1523275335684-37898b6baf30?q=80&w=1200&auto=format&fit=crop",
  },
  {
    id: 3,
    title: "Gaming Headset",
    category: "Gaming",
    price: "₹2,499",
    oldPrice: "₹4,499",
    image:
      "https://images.unsplash.com/photo-1505740420928-5e560c06d30e?q=80&w=1200&auto=format&fit=crop",
  },
  {
    id: 4,
    title: "Sony Camera",
    category: "Photography",
    price: "₹54,999",
    oldPrice: "₹68,999",
    image:
      "https://images.unsplash.com/photo-1516035069371-29a1b244cc32?q=80&w=1200&auto=format&fit=crop",
  },
];

export default function TrendingProductsSection() {
  return (
    <section className="relative py-20 bg-[#faf7f2] overflow-hidden">
      {/* BACKGROUND BLURS */}
      <div className="absolute top-0 left-0 w-[300px] h-[300px] bg-orange-200/30 blur-[120px] rounded-full" />

      <div className="absolute bottom-0 right-0 w-[300px] h-[300px] bg-yellow-100/40 blur-[120px] rounded-full" />

      <div className="w-full px-4 md:px-8 xl:px-14 relative z-10">
        {/* HEADER */}
        <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-6 mb-14">
          <div>
            <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-white border border-orange-100 shadow-sm">
              <Flame size={15} className="text-orange-500" />

              <span className="text-xs tracking-[3px] text-orange-500 uppercase font-bold">
                Trending Products
              </span>
            </div>

            <h2 className="mt-2 text-[28px] lg:text-[42px] leading-none font-extrabold text-black">
              Explore Trending <br />
              Collections
            </h2>
          </div>

          <Link
            href="/shop"
            className="group flex items-center gap-2 text-gray-800 hover:text-orange-500 transition-all duration-300"
          >
            <span className="text-sm font-semibold tracking-wide">
              View All Products
            </span>

            <ArrowRight
              size={18}
              className="group-hover:translate-x-1 transition-all duration-300"
            />
          </Link>
        </div>

        {/* PRODUCT GRID */}
        <div className="grid grid-cols-2 sm:grid-cols-2 xl:grid-cols-4 gap-6">
          {trendingProducts.map((product, index) => (
            <motion.div
              key={product.id}
              initial={{ opacity: 0, y: 60 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{
                duration: 0.6,
                delay: index * 0.1,
              }}
              viewport={{ once: true }}
              className="group cursor-pointer"
            >
              {/* IMAGE CARD */}
              <div className="relative pb-2.5">
                {/* SOLID BLUE BACKING CARD (extends below image, peeks from bottom) */}
                <div className="absolute inset-x-0 top-0 bottom-0 rounded-[26px] bg-gradient-to-b from-sky-300 to-blue-400" />

                <div className="relative h-[190px] w-full rounded-[26px] overflow-hidden bg-[#f2f2f2] shadow-[0_4px_14px_rgba(0,0,0,0.06)] group-hover:shadow-[0_10px_28px_rgba(0,0,0,0.1)] transition-all duration-500">
                  <Image
                    src={product.image}
                    alt={product.title}
                    fill
                    sizes="(max-width: 639px) 50vw, (max-width: 1279px) 50vw, 25vw"
                    className="object-cover group-hover:scale-105 transition-transform duration-700"
                  />

                  {/* RATING BADGE */}
                  <div className="absolute top-3 right-3 flex items-center gap-1 px-2.5 py-1 rounded-full bg-white/95 shadow-sm">
                    <Star size={12} className="fill-blue-500 text-blue-500" />
                    <span className="text-xs font-semibold text-gray-800">
                      {product.rating || "4.5"}
                    </span>
                  </div>
                </div>
              </div>

              {/* CONTENT */}
              <div className="pt-4 px-1">
                <h3 className="text-[15px] font-bold text-gray-900 truncate">
                  {product.title}
                </h3>
                <p className="mt-0.5 text-sm text-gray-500 truncate">
                  {product.category}
                </p>
                <p className="mt-1.5 text-base font-bold text-gray-900">
                  From {product.price}
                </p>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}