"use client";

import Image from "next/image";
import { Star } from "lucide-react";
import { motion } from "framer-motion";

const bestSellers = [
  {
    id: 1,
    title: "Premium Running Shoes",
    price: "$129",
    oldPrice: "$169",
    rating: 4.9,
    image:
      "https://images.unsplash.com/photo-1542291026-7eec264c27ff?q=80&w=1200&auto=format&fit=crop",
    tag: "Best Seller",
  },
  {
    id: 2,
    title: "Wireless Headphones",
    price: "$89",
    oldPrice: "$120",
    rating: 4.8,
    image:
      "https://images.unsplash.com/photo-1505740420928-5e560c06d30e?q=80&w=1200&auto=format&fit=crop",
    tag: "Trending",
  },
  {
    id: 3,
    title: "Luxury Smart Watch",
    price: "$199",
    oldPrice: "$249",
    rating: 4.9,
    image:
      "https://images.unsplash.com/photo-1523275335684-37898b6baf30?q=80&w=1200&auto=format&fit=crop",
    tag: "Hot Deal",
  },
  {
    id: 4,
    title: "Modern Sunglasses",
    price: "$59",
    oldPrice: "$89",
    rating: 4.7,
    image:
      "https://images.unsplash.com/photo-1511499767150-a48a237f0083?q=80&w=1200&auto=format&fit=crop",
    tag: "Popular",
  },
];

export default function BestSellersSection() {
  return (
    <section className="w-full bg-[#f8f8f8] py-20 px-4 md:px-10 lg:px-16 overflow-hidden">
      <div className="max-w-[1500px] mx-auto">
        {/* Heading */}
        <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-5 mb-14">
          <div>
            <p className="text-sm uppercase tracking-[5px] text-red-500 font-semibold mb-3">
              Top Products
            </p>

            <h2 className="text-4xl md:text-5xl font-extrabold text-black leading-tight">
              Best Sellers
            </h2>
          </div>

          <p className="text-gray-500 max-w-xl text-sm md:text-base leading-relaxed">
            Explore our most loved and highest-rated products picked by
            thousands of customers worldwide.
          </p>
        </div>

        {/* Products */}
        <div className="grid grid-cols-2 sm:grid-cols-2 xl:grid-cols-4 gap-6">
          {bestSellers.map((product, index) => (
            <motion.div
              key={product.id}
              initial={{ opacity: 0, y: 60 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              viewport={{ once: true }}
              className="group cursor-pointer"
            >
              {/* IMAGE CARD */}
              <div className="relative pb-2.5">
                {/* SOLID ORANGE BACKING CARD (extends below image, peeks from bottom) */}
                <div className="absolute inset-x-0 top-0 bottom-0 rounded-[26px] bg-gradient-to-b from-orange-300 to-orange-400" />

                <div className="relative h-[190px] w-full rounded-[26px] overflow-hidden bg-[#f2f2f2] shadow-[0_4px_14px_rgba(0,0,0,0.06)] group-hover:shadow-[0_10px_28px_rgba(0,0,0,0.1)] transition-all duration-500">
                  <Image
                    src={product.image}
                    alt={product.title}
                    fill
                    sizes="(max-width: 639px) 50vw, (max-width: 1279px) 50vw, 25vw"
                    className="object-cover group-hover:scale-105 transition-transform duration-700"
                  />

                  {/* RATING BADGE */}
                  <div className="absolute top-3 right-3 flex items-center gap-1 px-2.5 py-1 rounded-full bg-white/95 shadow-sm">
                    <Star size={12} className="fill-orange-500 text-orange-500" />
                    <span className="text-xs font-semibold text-gray-800">
                      {product.rating}
                    </span>
                  </div>
                </div>
              </div>

              {/* CONTENT */}
              <div className="pt-4 px-1">
                <h3 className="text-[15px] font-bold text-gray-900 truncate">
                  {product.title}
                </h3>
                <p className="mt-0.5 text-sm text-gray-500 truncate">
                  {product.tag}
                </p>
                <div className="mt-1.5 flex items-center gap-2">
                  <span className="text-base font-bold text-gray-900">
                    {product.price}
                  </span>
                  <span className="text-sm text-gray-400 line-through">
                    {product.oldPrice}
                  </span>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}